arguments.command:
# Check if there are dynamic symbols in the downloaded monosgen
aarch64-linux-gnu-nm -D /tmp/sv-f6f07fd6a9d6441d94c9795844949307/symbols/libmonosgen-2.0.so 2>/dev/null | wc -l
echo "---"
# Check specific addresses we need
# Frame #01: 0x222098, #02: 0x222234, #03: 0x19bac0, #06: 0x19bc14
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo "Addr $addr:"
  aarch64-linux-gnu-nm -D /tmp/sv-f6f07fd6a9d6441d94c9795844949307/symbols/libmonosgen-2.0.so 2>/dev/null | \
    awk -v target="$addr" '
    BEGIN { target_val = strtonum(target) }
    /^[0-9a-f]+ [TtWw]/ {
      sym_addr = strtonum("0x" $1);
      if (sym_addr <= target_val) {
        candidates[sym_addr] = $3;
      }
    }
    END {
      best = 0;
      for (a in candidates) {
        if (a > best) best = a;
      }
      if (best > 0) {
        printf "  %s + 0x%x\n", candidates[best], target_val - best;
      } else {
        print "  (no match)";
      }
    }'
done

